* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  background: transparent;
  display: flex;
  align-items: center;
  height: 100%;
  font-family: Inter, system-ui, sans-serif;
  overflow: hidden;
}

#badge span {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  padding: 15px 40px;
  border-radius: 30px;
  font-size: 13px;
  font-weight: 700;
}

srcDoc.js:
appsmith.onReady(function () {
  render();
});
appsmith.onModelChange(function () {
  render();
});
function render() {
  var value = appsmith.model.status;
  console.log('VALUE IS:', value);
  console.log('TYPE IS:', typeof value);
  var label, bg, color, border;
  if (value === true || value === 'true' || value === 1) {
    label = 'Yes';
    bg = '#EAF3DE';
    color = '#27500A';
    border = '#C0DD97';
  } else if (value === false || value === 'false' || value === 0) {
    label = 'No';
    bg = '#FCEBEB';
    color = '#A32D2D';
    border = '#FCA5A5';
  } else {
    label = 'Unknown';
    bg = '#F4F6F8';
    color = '#6B7280';
    border = '#E5E7EB';
  }
  document.getElementById('badge').innerHTML = '<span style="background:' + bg + ';color:' + color + ';border:1px solid ' + border + '">' + label + '</span>';
}

